      ArgChecker.isTrue(
          builder.attachmentPoint >= 0.0 && builder.attachmentPoint <= 1.0,
          "attachmentPoint must be between 0.0 and 1.0");
      ArgChecker.isTrue(
          builder.detachmentPoint >= 0.0 && builder.detachmentPoint <= 1.0,
          "detachmentPoint must be between 0.0 and 1.0");
      ArgChecker.isTrue(
          builder.attachmentPoint < builder.detachmentPoint,
          "attachmentPoint must be less than detachmentPoint");
    }
  }

