package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.market.sensitivity.PointSensitivityBuilder;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;

/**
 * Pricer for CDS tranches based on the ISDA standard model.
 * <p>
 * The implementation prices CDS tranches by calculating the expected loss
 * within the attachment and detachment points and applying the underlying
 * CDS index pricer to the tranche-specific notional.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT = new IsdaCdsTranchePricer();

  /**
   * The underlying CDS index pricer.
   */
  private final IsdaHomogenousCdsIndexProductPricer indexPricer;

  /**
   * Creates an instance using the default CDS index pricer.
   */
  public IsdaCdsTranchePricer() {
    this.indexPricer = new IsdaHomogenousCdsIndexProductPricer();
  }

  /**
   * Creates an instance with a specified CDS index pricer.
   *
   * @param indexPricer  the CDS index pricer, not null
   */
  public IsdaCdsTranchePricer(IsdaHomogenousCdsIndexProductPricer indexPricer) {
    this.indexPricer = ArgChecker.notNull(indexPricer, "indexPricer");
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the price of the CDS tranche product, which is the present value per unit notional.
   * <p>
   * This method can calculate the clean or dirty price, see {@link PriceType}.
   * If calculating the clean price, the accrued interest is calculated based on the step-in date.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the price
   */
  public double price(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    ArgChecker.notNull(tranche, "tranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(priceType, "priceType");
    ArgChecker.notNull(refData, "refData");

    // Price the underlying index
    double indexPrice = indexPricer.price(
        tranche.getUnderlyingIndex(),
        ratesProvider,
        referenceDate,
        priceType,
        refData);

    // For tranches, the price is adjusted for the attachment and detachment points
    // This is a simplified model - the actual implementation would involve
    // calculating the expected loss allocation to the tranche
    double tranchedPrice = calculateTranchedPrice(indexPrice, tranche);

    return tranchedPrice;
  }

  /**
   * Calculates the present value of the CDS tranche trade.
   * <p>
   * This is the price multiplied by the notional and converted to the settlement currency.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    double price = price(tranche, ratesProvider, referenceDate, priceType, refData);
    double notional = tranche.getUnderlyingIndex().getNotional();
    CurrencyAmount pv = CurrencyAmount.of(
        tranche.getUnderlyingIndex().getCurrency(),
        price * notional);

    return pv;
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the tranche-adjusted price.
   * <p>
   * This applies the attachment and detachment points to adjust the index price.
   *
   * @param indexPrice  the index price
   * @param tranche  the tranche
   * @return the tranche price
   */
  private double calculateTranchedPrice(double indexPrice, ResolvedCdsTranche tranche) {
    // Simplified tranche pricing model
    // In a full implementation, this would involve calculating the expected loss
    // within the attachment/detachment points and adjusting the spread accordingly
    double attachmentPoint = tranche.getAttachmentPoint();
    double detachmentPoint = tranche.getDetachmentPoint();
    double trancheWidth = detachmentPoint - attachmentPoint;

    // Apply tranche adjustment (simplified)
    return indexPrice * trancheWidth;
  }
}

